import{_ as t,o as s,c as i,a}from"./chunks/framework.8tiMeCK-.js";const n="/PenguinLab/assets/ch12_fig043.CiNIyjf8.webp",o="/PenguinLab/assets/ch12_fig044.BWbtcCYP.webp",g=JSON.parse('{"title":"12.2  802.11 MAC Header","description":"","frontmatter":{},"headers":[],"relativePath":"en/notes/linux_kernel_networking/ch12_2.md","filePath":"en/notes/linux_kernel_networking/ch12_2.md","lastUpdated":null}'),r={name:"en/notes/linux_kernel_networking/ch12_2.md"};function l(h,e,d,p,c,u){return s(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="_12-2-802-11-mac-header" tabindex="-1">12.2 802.11 MAC Header <a class="header-anchor" href="#_12-2-802-11-mac-header" aria-label="Permalink to &quot;12.2  802.11 MAC Header&quot;">​</a></h1><hr><p>Each MAC frame consists of a MAC header, a frame body of variable length, and an FCS (Frame Check Sequence) of 32 bit CRC. Figure 12-1 shows the 802.11 header.</p><p><img src="'+n+`" alt="figure"></p><p>Figure 12-1. IEEE 802.11 header. Note that all members are not always used, as this section will shortly explain</p><p>346</p><p>Chapter 12 ■ Wireless in Linux</p><p>The 802.11 header is represented in mac80211 by the ieee80211_hdr structure:</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ieee80211_hdr {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        __le16 frame_control;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        __le16 duration_id;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        u8 </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">addr1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">];</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        u8 </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">addr2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">];</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        u8 </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">addr3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">];</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        __le16 seq_ctrl;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        u8 </span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">addr4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">];</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} __packed;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p><em>(include/linux/ieee80211.h)</em></p><p>If you&#39;re used to Ethernet (<code>struct ethhdr</code>), this structure might feel a bit &quot;heavy&quot; — an Ethernet header has only three fields: source MAC, destination MAC, and EtherType. The 802.11 header, on the other hand, can contain up to 4 or even 6 addresses (counting the two in the Mesh extension header), plus a bunch of control bits.</p><p>Don&#39;t let this &quot;luxury lineup&quot; intimidate you. In a typical data frame (like a phone talking to a router), only 3 addresses are actually used. For a simple ACK frame, only a single address is used. Figure 12-1 shows only 4 addresses, because Mesh networks use a special extension header to squeeze in two more.</p><p>Let&#39;s break down this header. We&#39;ll start with the first field — frame control. These 16 bits are very important; in many cases, they determine how the subsequent fields (especially those addresses) should be interpreted.</p><h3 id="the-frame-control" tabindex="-1">The Frame Control <a class="header-anchor" href="#the-frame-control" aria-label="Permalink to &quot;The Frame Control&quot;">​</a></h3><p>The frame control field is 16 bits long, structured as shown in Figure 12-2.</p><p><img src="`+o+'" alt="figure"></p><p><strong>Figure 12-2.</strong> Frame control fields</p><p>Think of it as a master switch panel, where each bit has a specific meaning. Let&#39;s look at each member:</p><ul><li><p><strong>Protocol Version</strong>: Identifies the 802.11 MAC version. Currently there is only one version, so this field is always 0. You can think of it as a &quot;legacy placeholder,&quot; or space reserved for possible major protocol revisions in the future.</p></li><li><p><strong>Type</strong>: 802.11 divides packets into three major categories: management, control, and data.</p><ul><li><strong>Management packets (<code>IEEE80211_FTYPE_MGMT</code>)</strong>: These are &quot;management signaling.&quot; For example, to connect to WiFi, you must first authenticate and then associate, or if you want to scan for nearby APs, all of these are management frames. Without them, you can&#39;t even connect to the network, let alone transmit data.</li><li><strong>Control packets (<code>IEEE80211_FTYPE_CTL</code>)</strong>: These typically assist data transmission. The most classic example is PS-Poll, used by a sleeping station to request data from an AP. Another well-known combination is RTS/CTS: before sending data, you first send an RTS (Request to Send); if the channel is free, the receiver sends back a CTS (Clear to Send), and then you send the data. This is designed to solve the &quot;hidden node&quot; problem by reserving the channel upfront to avoid collisions.</li><li><strong>Data packets (<code>IEEE80211_FTYPE_DATA</code>)</strong>: This is the actual data we want to transmit. There is a special case here called <strong>Null packets</strong>. Although they are of data frame type, they carry no payload. They are mainly used to notify the AP: &quot;I&#39;m going to sleep&quot; or &quot;I&#39;m awake.&quot; We&#39;ll cover this in detail in the &quot;Power Save Mode&quot; section later.</li></ul></li><li><p><strong>Subtype</strong>: Each of the three categories above has finer subdivisions, and that&#39;s what the Subtype field does. It&#39;s the &quot;specific identity&quot; of the frame.</p><ul><li>For management frames, if the Subtype is <code>0100</code>, it&#39;s a <strong>Probe Request</strong> (<code>IEEE80211_STYPE_PROBE_REQ</code>) — the &quot;who&#39;s out there?&quot; shout your phone makes when scanning for networks.</li><li>For control frames, Subtype <code>1011</code> represents <strong>RTS</strong> (<code>IEEE80211_STYPE_RTS</code>).</li><li>For data frames, Subtype <code>0100</code> represents <strong>Null Data</strong> (<code>IEEE80211_STYPE_NULLFUNC</code>).</li><li>Another key value is <code>1000</code> (<code>IEEE80211_STYPE_QOS_DATA</code>), representing a <strong>QoS data frame</strong>. This was added by the 802.11e amendment, primarily to support latency-sensitive applications like voice and video — what we commonly call &quot;high-priority queues.&quot;</li></ul></li><li><p><strong>ToDS / FromDS (To Distribution System / From DS)</strong>: These two bits indicate the direction of data flow, especially in infrastructure mode with an AP (Access Point).</p><ul><li><strong>ToDS = 1</strong>: Indicates the packet is destined for the Distribution System (DS). Simply put, it&#39;s a client sending to the AP, asking the AP to forward it into the LAN.</li><li><strong>FromDS = 1</strong>: Indicates the packet is coming from the Distribution System. Simply put, it&#39;s the AP sending to the client.</li></ul><p>There&#39;s an interesting combination here: if both bits are 1, it represents a frame being transmitted in a Wireless Distribution System (WDS), meaning two APs are backhauling data over wireless. In this case, you&#39;ll use all 4 addresses (covered in detail below).</p></li><li><p><strong>More Frag</strong>: When fragmentation is enabled, this bit is set to 1. If a packet is too large and gets chopped into several fragments, all but the last one have this bit set to 1, telling the receiver &quot;I&#39;m not done yet, don&#39;t rush.&quot;</p></li><li><p><strong>Retry</strong>: If this packet is a retransmission, this bit is 1. 802.11 runs over an unreliable wireless link, so packet loss is normal. If a sent packet doesn&#39;t receive an ACK, the sender must retransmit. This bit tells the receiver: &quot;Don&#39;t mind the repetition — the previous one was probably lost, this is a resend.&quot;</p></li><li><p><strong>Pwr Mgmt</strong>: When this bit is set to 1, it means the station is about to enter power save mode. When the AP sees this bit, it understands: &quot;Don&#39;t drop data destined for this station — buffer it for me, and they&#39;ll request it when they wake up.&quot; We&#39;ll cover this complex &quot;sleep-wake&quot; mechanism in detail later.</p></li><li><p><strong>More Data</strong>: This is the AP&#39;s response to a sleeping station. When the AP sends packets to a sleeping station, if its buffer still has data left to send, it sets this bit to 1. When the station sees this bit, it knows: even though it just received one packet, it needs to stay awake or quickly send a PS-Poll to get another batch, because there&#39;s more coming. When the buffer is empty, this bit goes back to 0.</p></li><li><p><strong>Protected Frame</strong>: If this bit is 1, it means the frame body is encrypted. Only data frames and authentication frames can be encrypted.</p></li><li><p><strong>Order</strong>: If the &quot;strict ordering&quot; MAC service is in use, this bit is set to 1. It&#39;s a mechanism to guarantee frames arrive in order, but it&#39;s rarely used nowadays.</p></li></ul><blockquote><p><strong>⚠️ Note</strong> The <strong>Action Frame</strong> (<code>IEEE80211_STYPE_ACTION</code>) was originally introduced by 802.11h, mainly for spectrum management and transmit power control. But later, because the management frame subtype space ran out, many newer standards (like HT operations in 802.11n) repurposed Action Frames to carry information. It&#39;s like a universal envelope — what&#39;s inside depends on the specific protocol amendment.</p></blockquote><h3 id="the-other-802-11-mac-header-members" tabindex="-1">The Other 802.11 MAC Header Members <a class="header-anchor" href="#the-other-802-11-mac-header-members" aria-label="Permalink to &quot;The Other 802.11 MAC Header Members&quot;">​</a></h3><p>Besides frame control, the 802.11 header has several other key players:</p><ul><li><p><strong>Duration/ID</strong>: This field is typically used to set the <strong>NAV (Network Allocation Vector)</strong>, a virtual carrier sensing mechanism. Simply put, it tells everyone nearby: &quot;I&#39;m going to occupy the channel for this long — hold your tongue and do the math.&quot; It consists of 15 bits, with the most significant bit (the 16th) being 0.</p><p>But in power save mode, this field has a special purpose: for PS-Poll frames, it carries the station&#39;s <strong>AID (Association ID)</strong>. The AID is a number assigned by the AP to each connected device, and it&#39;s crucial in the sleep-wake mechanism.</p></li><li><p><strong>Sequence Control</strong>: This is a 2-byte field consisting of two parts:</p><ul><li><strong>Fragment Number (4 bits)</strong>: The fragment number.</li><li><strong>Sequence Number (12 bits)</strong>: The sequence number.</li></ul><p>Out-of-order delivery and packet loss are common in wireless environments. The sender generates the sequence number in the <code>ieee80211_tx_h_sequence()</code> method. If the receiver gets a packet with the exact same sequence number as a previous one (usually because the ACK was lost, causing the sender to retransmit), mac80211&#39;s <code>ieee80211_rx_h_check()</code> method treats it as a duplicate frame, drops it, and increments the <code>dot11FrameDuplicateCount</code> counter.</p><p><strong>Note</strong>: Control frames typically do not have this field.</p></li><li><p><strong>Address 1 – Address 4</strong>: This is the most confusing part. Why does a packet need 4 addresses?</p><ul><li><strong>Address 1 (RA, Receiver Address)</strong>: The receiver address. All packets have this, telling the NIC &quot;who this is for.&quot;</li><li><strong>Address 2 (TA, Transmitter Address)</strong>: The transmitter address. Most packets have this (except for ultra-short control frames like ACK and CTS), telling the NIC &quot;who sent this.&quot;</li><li><strong>Address 3</strong>: Used mainly for management and data frames. In infrastructure mode (with an AP), it&#39;s typically the source or destination address (depending on the ToDS/FromDS settings). For example, in a data packet from your phone to your computer, even though it&#39;s forwarded through the AP, Address 3 is still the computer&#39;s MAC address.</li><li><strong>Address 4</strong>: This only appears in special cases — when both ToDS and FromDS are <strong>set to 1</strong>. This usually happens in WDS (Wireless Distribution System) or Mesh networks, representing the ultimate source or destination of a packet that has traversed multiple wireless hops.</li></ul></li><li><p><strong>QoS Control</strong>: This was added by the 802.11e amendment and is only present in QoS data packets. Because it wasn&#39;t part of the original 802.11 spec, it&#39;s not a member of the standard <code>ieee80211_hdr</code> structure. If you look for it in the code, it&#39;s actually appended after the header. mac80211 provides the <code>ieee80211_get_qos_ctl()</code> method to access it.</p><p>This field contains the <strong>TID (Traffic Identifier)</strong>, <strong>ACK Policy</strong> (e.g., whether to use Block Ack), and the <strong>A-MSDU present</strong> flag (telling you if this is an aggregated frame). We&#39;ll dive into A-MSDU in the &quot;High Throughput (802.11n)&quot; section later.</p></li><li><p><strong>HT Control Field</strong>: This was added by the 802.11n amendment for High Throughput operations. See section 7.1.3.5(a) of the 802.11n-2009 spec.</p></li></ul><p>This section broke down the 802.11 MAC header and examined every one of its members. Becoming familiar with this structure is fundamental to understanding the mac80211 stack, because nearly every byte your driver handles has its logic defined right here.</p><p>Now that we know what frames look like, we need to consider: how do these frames flow between different devices? This brings us to network topologies and the MAC Layer Management Entity (MLME).</p>',25)])])}const k=t(r,[["render",l]]);export{g as __pageData,k as default};
